def _user_auth_client():
    """Separate client for end-user sign-in so user JWTs never attach to service-role `sb`."""
    return create_client(SUPABASE_URL, SUPABASE_KEY)

def _sign_in_with_password_as_user(email: str, password: str):
    """Return a user session without touching the shared service-role client."""
    return _user_auth_client().auth.sign_in_with_password({"email": email, "password": password})
IMAGE_BUCKETS = {"offers", "promotions"}
MAX_IMAGE_BYTES = 5 * 1024 * 1024
ALLOWED_IMAGE_TYPES = {"image/jpeg", "image/png", "image/webp", "image/gif"}
IMAGE_EXT = {"image/jpeg": "jpg", "image/png": "png", "image/webp": "webp", "image/gif": "gif"}

def public_image_url(bucket: str, key: Optional[str]) -> Optional[str]:
    if not key or not sb:
        return None
    try:
        return sb.storage.from_(bucket).get_public_url(key)
    except Exception:
        if SUPABASE_URL:
            return f"{SUPABASE_URL}/storage/v1/object/public/{bucket}/{key}"
        return None

def enrich_image(record: dict, bucket: str) -> dict:
    if not record:
        return record
    out = dict(record)
    key = out.get("image_key")
    if key:
        out["image_url"] = public_image_url(bucket, key)
    return out

def delete_storage_object(bucket: str, key: Optional[str]):
    if not sb or not key or bucket not in IMAGE_BUCKETS:
        return
    try:
        sb.storage.from_(bucket).remove([key])
    except Exception:
        pass

def _normalize_lang_codes(langs: Optional[list]) -> list:
    if not langs:
        return []
    out = []
    seen = set()
    for raw in langs:
        code = (raw or "").strip().lower()
        if not code or code in seen:
            continue
        seen.add(code)
        out.append(code)
    return out

