def _attach_regions_to_offers(offers: list) -> list:
    if not sb or not offers:
        return offers
    ids = [o.get("id") for o in offers if o.get("id") is not None]
    if not ids:
        return offers
    try:
        rows = (
            sb.table("offer_regions")
            .select("offer_id, region_id, regions(id, name, languages, active, is_deleted)")
            .in_("offer_id", ids)
            .execute()
            .data
            or []
        )
    except Exception:
        return offers
    by_offer: dict = {}
    for row in rows:
        oid = row.get("offer_id")
        reg = row.get("regions")
        if oid is None or not reg or not _region_is_visible(reg):
            continue
        by_offer.setdefault(oid, []).append(reg)
    for o in offers:
        regs = by_offer.get(o.get("id"), [])
        o["regions"] = regs
        o["region_ids"] = [r.get("id") for r in regs if r.get("id")]
    return offers

