def _creator_name_map(user_ids: list) -> dict:
    """Resolve public.users id → display name (name, else email)."""
    if not sb or not user_ids:
        return {}
    ids = list({str(uid) for uid in user_ids if uid})
    if not ids:
        return {}
    try:
        res = sb.table("users").select("id,name,email").in_("id", ids).execute()
    except Exception:
        return {}
    out: dict = {}
    for row in res.data or []:
        uid = row.get("id")
        if not uid:
            continue
        name = (row.get("name") or "").strip()
        email = (row.get("email") or "").strip()
        out[str(uid)] = name or email or "Unknown"
    return out

