def _promotion_region_langs(promotion_id) -> list:
    if not sb or not promotion_id:
        return []
    try:
        rows = (
            sb.table("promotion_regions")
            .select("regions(languages, active)")
            .eq("promotion_id", promotion_id)
            .execute()
            .data
            or []
        )
    except Exception:
        return []
    langs = set()
    for row in rows:
        reg = row.get("regions") or {}
        if reg.get("active") is False:
            continue
        for code in reg.get("languages") or []:
            if code:
                langs.add(code)
    return list(langs)

def _build_region_lang_map(junction_table: str, entity_id_col: str, entity_ids: list):
    """Return (has_regions, region_langs) maps keyed by entity id."""
    has_regions: dict = {}
    region_langs: dict = {}
    if not sb or not entity_ids:
        return has_regions, region_langs
    try:
        rows = (
            sb.table(junction_table)
            .select(f"{entity_id_col}, regions(languages, active)")
            .in_(entity_id_col, entity_ids)
            .execute()
            .data
            or []
        )
    except Exception:
        return has_regions, region_langs
    for row in rows:
        eid = row.get(entity_id_col)
        reg = row.get("regions") or {}
        if eid is None or reg.get("active") is False:
            continue
        has_regions[eid] = True
        region_langs.setdefault(eid, set()).update(
            c for c in (reg.get("languages") or []) if c
        )
    return has_regions, region_langs

def _offer_matches_lang(offer: dict, lang: str, has_regions: dict, region_langs: dict) -> bool:
    offer_lang = offer.get("lang") or "all"
    if offer_lang != "all" and offer_lang != lang:
        return False
    oid = offer.get("id")
    if has_regions.get(oid) and lang not in region_langs.get(oid, set()):
        return False
    return True

def _promotion_matches_lang_regions(
    promotion_id, lang: str, has_regions: dict, region_langs: dict
) -> bool:
    if not lang:
        return True
    if not has_regions.get(promotion_id):
        return True
    return lang in region_langs.get(promotion_id, set())

def _promotion_matches_lang(promo: dict, lang: Optional[str]) -> bool:
    if not lang:
        return True
    langs = _promotion_region_langs(promo.get("id"))
    if not langs:
        return True
    return lang in langs

def _fetch_active_offers_filtered(lang: str) -> list:
    from datetime import date
    today = date.today()
    result = sb.table(OFFERS_TABLE).select("*").eq("active", True).eq("is_deleted", False).order("id", desc=True).execute()
    offers = result.data or []
    ids = [o.get("id") for o in offers if o.get("id") is not None]
    has_regions, region_langs = _build_region_lang_map("offer_regions", "offer_id", ids)
    filtered = []
    for o in offers:
        if o.get("expires_at"):
            try:
                if date.fromisoformat(o["expires_at"]) < today:
                    continue
            except Exception:
                pass
        if not _offer_matches_lang(o, lang, has_regions, region_langs):
            continue
        filtered.append(o)
    return filtered

def _fetch_active_promotions_filtered(lang: str) -> list:
    from datetime import date
    today = date.today()
    result = (
        sb.table("promotions")
        .select("*")
        .eq("active", True)
        .eq("is_deleted", False)
        .order("created_at", desc=True)
        .execute()
    )
    promos = result.data or []
    ids = [p.get("id") for p in promos if p.get("id") is not None]
    has_regions, region_langs = _build_region_lang_map("promotion_regions", "promotion_id", ids)
    filtered = []
    for p in promos:
        if p.get("expires_at"):
            try:
                if date.fromisoformat(p["expires_at"]) < today:
                    continue
            except Exception:
                pass
        if not _promotion_matches_lang_regions(p.get("id"), lang, has_regions, region_langs):
            continue
        filtered.append(p)
    return filtered

def get_embedding(text):
    r = requests.post(EMBED_URL, json={"model": "models/gemini-embedding-001", "content": {"parts": [{"text": text}]}}, timeout=10)
    r.raise_for_status()
    return r.json()["embedding"]["values"]

def retrieve_context(query, top_k=4, threshold=0.3):
    if not sb:
        return []
    try:
        emb = get_embedding(query)
        result = sb.rpc("match_chunks", {"query_embedding": emb, "match_count": top_k, "match_threshold": threshold}).execute()
        return result.data or []
    except Exception:
        return []

def build_rag_context(chunks):
    if not chunks:
        return ""
    parts = [f"[{c.get('metadata', {}).get('title', '?')}]\n{c['content']}" for c in chunks]
    return "\n---\n".join(parts)

def _describe_child_age(birth_date_str):
    from datetime import date
    try:
        birth = date.fromisoformat(birth_date_str)
        today = date.today()
        months = (today.year - birth.year) * 12 + (today.month - birth.month)
        if today.day < birth.day:
            months -= 1
        months = max(0, months)
        if months < 1:
            days = (today - birth).days
            return f"{max(0, days)} days old"
        elif months < 24:
            return f"{months} months old"
        else:
            years = months // 12
            rem = months % 12
            return f"{years} years{f' and {rem} months' if rem else ''} old"
    except Exception:
        return "unknown age"

def build_profile_context(profile):
    if not profile:
        return ""
    from datetime import date
    lines = []
    children = []
    if profile.children:
        for c in profile.children:
            if c.name:
                children.append({"name": c.name, "birthDate": c.birthDate})
    if not children and profile.childName:
        children.append({"name": profile.childName, "birthDate": profile.childBirthDate, "ageFallback": profile.childAge})
    due_date_passed = False
    if profile.dueDate:
        try:
            due = date.fromisoformat(profile.dueDate)
            today = date.today()
            days_left = (due - today).days
            gestational_days = 280 - days_left
            week = max(1, min(42, gestational_days // 7))
            if days_left > 0:
                lines.append(f"This user is currently pregnant, approximately {week} weeks pregnant. Expected due date: {profile.dueDate} ({days_left} days remaining).")
            else:
                due_date_passed = True
        except Exception:
            lines.append(f"This user is currently pregnant. Expected due date: {profile.dueDate}.")
    if due_date_passed and not children:
        lines.append(
            "IMPORTANT - HANDLE WITH CARE: This user's expected due date has passed, but no baby has been "
            "registered in their profile yet. DO NOT proactively bring up the pregnancy, due date, birth, or "
            "ask about the baby's arrival. Do NOT assume anything about the outcome. Wait for the user to "
            "bring up the topic themselves. If they mention they have given birth and the baby is healthy, "
            "warmly congratulate them and ask for the baby's date of birth (and name, if they'd like to share it) "
            "so their profile can be updated. If they indicate difficulty, loss, or a complication, respond with "
            "warmth and care, do not proceed with any profile/baby setup, and gently suggest they reach out to "
            "their doctor or a trusted person for support if appropriate. If the user has not brought up the "
            "topic, keep greetings and proactive messages neutral and general (e.g. simply ask how they are doing today)."
        )
    for child in children:
        name = child.get("name") or "their child"
        if child.get("birthDate"):
            age_desc = _describe_child_age(child["birthDate"])
        else:
            age_desc = child.get("ageFallback") or "unknown age"
        lines.append(f"This user has a child named {name}, currently {age_desc}.")
    if len(children) > 1:
        lines.append(
            "This user has multiple children. Pay close attention to which child the user is referring to in "
            "their current message (by name or context) and respond about that specific child, not a different "
            "one or the pregnancy."
        )
    if children and profile.dueDate and not due_date_passed:
        lines.append(
            "This user has both a registered child/children AND an ongoing pregnancy. When the user refers to "
            "'the baby' or asks about development without specifying, infer from context whether they mean the "
            "born child or the pregnancy, and ask for clarification if it's ambiguous."
        )
    return "\n".join(lines)
