def invalidate_system_prompt_cache():
    global _system_prompt_cache
    _system_prompt_cache = None

def _fetch_chat_prompt_row():
    if not sb:
        return None
    try:
        res = (
            sb.table(CHAT_PROMPT_SETTINGS_TABLE)
            .select("content,updated_at,updated_by")
            .eq("key", CHAT_PROMPT_KEY)
            .limit(1)
            .execute()
        )
        rows = res.data or []
        return rows[0] if rows else None
    except Exception:
        return None

def get_system_prompt_content() -> str:
    global _system_prompt_cache
    if _system_prompt_cache is not None:
        return _system_prompt_cache
    row = _fetch_chat_prompt_row()
    if row and (row.get("content") or "").strip():
        _system_prompt_cache = row["content"].strip()
        return _system_prompt_cache
    _system_prompt_cache = DEFAULT_SYSTEM_PROMPT
    return _system_prompt_cache

def build_system_prompt(rag_context, family_context="", memories_context="", docs_context="", promotion_context=""):
    prompt = get_system_prompt_content()
    if family_context:
        prompt += f"\n\n--- About this user ---\n{family_context}"
    if memories_context:
        prompt += f"\n\n--- Recent memories this user has saved (use naturally if relevant, never list them all at once) ---\n{memories_context}"
    if docs_context:
        prompt += f"\n\n--- Document archive (act as librarian: you know what documents exist and for whom, but NEVER read or comment on their content. Only mention their existence when naturally relevant) ---\n{docs_context}"
    if promotion_context:
        prompt += "\n\n--- Sponsored content (mention ONLY if it naturally fits the current conversation topic, in at most one brief sentence translated into the user language, ALWAYS followed by the word sponsored in parentheses) ---\n" + promotion_context
    if rag_context:
        prompt += f"\n\n--- Background knowledge (use naturally, don't cite) ---\n{rag_context}"
    return prompt

COMPLEX_KEYWORDS = ["diagnosis","symptoms","emergency","medication","fever","hospital","allergy","depression","anxiety"]

GEMINI_FIRST_LANGS = {"ar","zh","ja","hi","ur","bn","mr","te","fil","sw"}
CLAUDE_FIRST_LANGS = set()

import re as _re
def detect_msg_lang(message: str, profile_lang: str = "") -> str:
    if _re.search(r'[\u0600-\u06FF]', message):
        return "ur" if _re.search(r'[\u067E\u0679\u0688\u0691]', message) else "ar"
    if _re.search(r'[\u3040-\u30FF]', message): return "ja"
    if _re.search(r'[\u4E00-\u9FFF]', message): return "zh"
    if _re.search(r'[\u0980-\u09FF]', message): return "bn"
    if _re.search(r'[\u0C00-\u0C7F]', message): return "te"
    if _re.search(r'[\u0900-\u097F]', message): return profile_lang if profile_lang in ("hi","mr") else "hi"
    if _re.search(r'[\u0400-\u04FF]', message): return "ru"
    if _re.search(r'[\u0370-\u03FF\u1F00-\u1FFF]', message): return "el"
    return profile_lang or "en"

def is_complex(message):
    return any(kw in message.lower() for kw in COMPLEX_KEYWORDS) or len(message) > 300

def _api_error(
    status_code: int,
    code: str,
    friendly_message: str,
    detail: str = "",
):
    raise HTTPException(
        status_code=status_code,
        detail={
            "code": code,
            "detail": detail or friendly_message,
            "friendly_message": friendly_message,
        },
    )

def resolve_auth(token: str, *, context: str = "app"):
    """Validate x-token: beta invite code or Supabase JWT access token."""
    token = (token or "").strip()
    if not token:
        if context == "admin":
            _api_error(
                401,
                "missing_token",
                "You are not signed in. Please log in to the admin panel.",
                "Missing x-token header",
            )
        _api_error(
            401,
            "missing_token",
            "No login token was sent. Sign in to HeyMaa or enter a valid beta invite code.",
            "Missing x-token header",
        )
    if is_valid_invite_code(token):
        return {"kind": "invite", "token": token, "user_id": None}
    if sb:
        try:
            user_res = sb.auth.get_user(token)
            if user_res and user_res.user:
                return {"kind": "user", "token": token, "user_id": user_res.user.id}
        except Exception:
            pass
    if context == "admin":
        _api_error(
            401,
            "invalid_session",
            "Your admin session has expired or is invalid. Please sign in again.",
            "Invalid or expired token",
        )
    _api_error(
        401,
        "invalid_token",
        "Your session has expired or is not valid. Please sign in again.",
        "Invalid or expired token",
    )

def verify_token(token: str):
    resolve_auth(token)

def profile_query(auth: dict):
    if auth["kind"] == "invite":
        return sb.table("profiles").select("*").eq("token", auth["token"])
    return sb.table("profiles").select("*").eq("user_id", auth["user_id"])

def profile_upsert_base(auth: dict) -> dict:
    if auth["kind"] == "invite":
        return {"token": auth["token"]}
    return {"user_id": auth["user_id"]}

def profile_upsert(auth: dict, fields: dict) -> None:
    """Insert or update the profile row for this invite token or auth user."""
    base = profile_upsert_base(auth)
    if auth["kind"] == "invite":
        existing = sb.table("profiles").select("token").eq("token", auth["token"]).execute()
        if existing.data:
            sb.table("profiles").update(fields).eq("token", auth["token"]).execute()
        else:
            sb.table("profiles").insert({**base, **fields}).execute()
    else:
        existing = sb.table("profiles").select("user_id").eq("user_id", auth["user_id"]).execute()
        if existing.data:
            sb.table("profiles").update(fields).eq("user_id", auth["user_id"]).execute()
        else:
            # Auth users: user_id only (token stays null after profiles_auth_user_id.sql).
            # Pre-migration fallback if token is still NOT NULL in DB.
            payload = {**base, **fields}
            try:
                sb.table("profiles").insert(payload).execute()
            except Exception as e:
                err = str(e)
                if "token" in err and "not-null" in err.lower() and "user_id" in payload:
                    payload["token"] = str(payload["user_id"])
                    sb.table("profiles").insert(payload).execute()
                else:
                    raise

def user_data_upsert(auth: dict, key: str, value, updated_at: str) -> None:
    """Insert or update a user_data row for this invite token or auth user."""
    fields = {"key": key, "value": value, "updated_at": updated_at}
    if auth["kind"] == "invite":
        existing = sb.table("user_data").select("key").eq("token", auth["token"]).eq("key", key).execute()
        if existing.data:
            sb.table("user_data").update(fields).eq("token", auth["token"]).eq("key", key).execute()
        else:
            sb.table("user_data").insert({**profile_upsert_base(auth), **fields}).execute()
    else:
        existing = sb.table("user_data").select("key").eq("user_id", auth["user_id"]).eq("key", key).execute()
        if existing.data:
            sb.table("user_data").update(fields).eq("user_id", auth["user_id"]).eq("key", key).execute()
        else:
            payload = {"user_id": auth["user_id"], **fields}
            try:
                sb.table("user_data").insert(payload).execute()
            except Exception as e:
                err = str(e)
                if "token" in err and "not-null" in err.lower():
                    payload["token"] = str(auth["user_id"])
                    sb.table("user_data").insert(payload).execute()
                else:
                    raise

USER_DATA_SUMMARY_KEYS = ("family", "chat", "memories", "threads")
EMPTY_USER_DATA_SUMMARY = {
    "children": 0,
    "members": 0,
    "chat_messages": 0,
    "memories": 0,
    "threads": 0,
}

def _parse_stored_user_data_value(value):
    import json
    if value is None:
        return None
    if isinstance(value, (dict, list, int, float, bool)):
        return value
    if isinstance(value, str):
        s = value.strip()
        if not s:
            return None
        try:
            return json.loads(s)
        except Exception:
            return value
    return value

def _family_counts(value) -> tuple:
    parsed = _parse_stored_user_data_value(value)
    if parsed is None:
        return 0, 0
    if isinstance(parsed, list):
        return 0, len(parsed)
    if isinstance(parsed, dict):
        children = parsed.get("children") or []
        members = parsed.get("members") or []
        child_n = len(children) if isinstance(children, list) else 0
        member_n = len(members) if isinstance(members, list) else 0
        return child_n, member_n
    return 0, 0

def _stored_list_count(value) -> int:
    parsed = _parse_stored_user_data_value(value)
    return len(parsed) if isinstance(parsed, list) else 0

def _apply_user_data_summary(summary: dict, key: str, value) -> None:
    if key == "family":
        child_n, member_n = _family_counts(value)
        summary["children"] = child_n
        summary["members"] = member_n
    elif key == "chat":
        summary["chat_messages"] = _stored_list_count(value)
    elif key == "memories":
        summary["memories"] = _stored_list_count(value)
    elif key == "threads":
        summary["threads"] = _stored_list_count(value)

def _user_data_summaries_for_users(user_ids: list) -> dict:
    if not sb or not user_ids:
        return {}
    ids = [uid for uid in user_ids if uid]
    if not ids:
        return {}
    summaries = {uid: dict(EMPTY_USER_DATA_SUMMARY) for uid in ids}
    seen_keys = {uid: set() for uid in ids}

    def ingest(uid, key, value):
        if uid not in summaries or not key or key in seen_keys[uid]:
            return
        seen_keys[uid].add(key)
        _apply_user_data_summary(summaries[uid], key, value)

    for offset in range(0, len(ids), 100):
        chunk = ids[offset : offset + 100]
        res = (
            sb.table("user_data")
            .select("user_id,key,value")
            .in_("user_id", chunk)
            .in_("key", list(USER_DATA_SUMMARY_KEYS))
            .execute()
        )
        for row in res.data or []:
            ingest(row.get("user_id"), row.get("key"), row.get("value"))

    try:
        prof = (
            sb.table("profiles")
            .select("user_id,token")
            .in_("user_id", ids)
            .not_.is_("token", "null")
            .execute()
        )
        token_map = {
            p["token"]: p["user_id"]
            for p in (prof.data or [])
            if p.get("token") and p.get("user_id")
        }
        tokens = list(token_map.keys())
        for offset in range(0, len(tokens), 100):
            tchunk = tokens[offset : offset + 100]
            res2 = (
                sb.table("user_data")
                .select("token,key,value")
                .in_("token", tchunk)
                .in_("key", list(USER_DATA_SUMMARY_KEYS))
                .execute()
            )
            for row in res2.data or []:
                uid = token_map.get(row.get("token"))
                if uid:
                    ingest(uid, row.get("key"), row.get("value"))
    except Exception:
        pass

    return summaries

def _paginate_table_rows(table: str, columns: str, order_col: str = "created_at") -> list:
    """Fetch all rows (Supabase/PostgREST caps each request at ~1000 rows)."""
    rows: list = []
    page_size = 1000
    offset = 0
    while True:
        end = offset + page_size - 1
        res = (
            sb.table(table)
            .select(columns)
            .order(order_col, desc=True)
            .range(offset, end)
            .execute()
        )
        batch = res.data or []
        rows.extend(batch)
        if len(batch) < page_size:
            break
        offset += page_size
    return rows

def _list_all_auth_users() -> list:
    """All auth.users via admin API (paginated)."""
    users: list = []
    page = 1
    per_page = 1000
    while True:
        res = sb.auth.admin.list_users(page=page, per_page=per_page)
        batch = []
        if isinstance(res, list):
            batch = res
        elif hasattr(res, "users"):
            batch = res.users or []
        elif isinstance(res, dict):
            batch = res.get("users") or []
        if not batch:
            break
        users.extend(batch)
        if len(batch) < per_page:
            break
        page += 1
    return users

def _auth_user_row(auth_user) -> dict:
    """Normalize auth user object/dict for admin list merge."""
    if isinstance(auth_user, dict):
        uid = auth_user.get("id")
        email = auth_user.get("email") or ""
        meta = auth_user.get("user_metadata") or {}
        created = auth_user.get("created_at")
    else:
        uid = getattr(auth_user, "id", None)
        email = getattr(auth_user, "email", None) or ""
        meta = getattr(auth_user, "user_metadata", None) or {}
        created = getattr(auth_user, "created_at", None)
    name = meta.get("name") if isinstance(meta, dict) else None
    return {
        "id": uid,
        "email": email,
        "name": name,
        "plan": None,
        "subscription_status": "auth_only",
        "trial_ends_at": None,
        "created_at": created,
        "last_login": None,
        "role": None,
        "account_kind": "auth_only",
    }

def _subscription_active_for_user(user_id: str) -> bool:
    """Registered Supabase users: active plan or unexpired trial."""
    res = sb.table("users").select("subscription_status,trial_ends_at,role").eq("id", user_id).execute()
    if not res.data:
        return False
    row = res.data[0]
    if row.get("role") == "admin":
        return True
    status = (row.get("subscription_status") or "").lower()
    if status == "active":
        return True
    if status == "trial":
        trial_ends = row.get("trial_ends_at")
        if not trial_ends:
            return True
        from datetime import datetime, timezone
        try:
            exp_dt = datetime.fromisoformat(str(trial_ends).replace("Z", "+00:00"))
            if exp_dt.tzinfo is None:
                exp_dt = exp_dt.replace(tzinfo=timezone.utc)
            return exp_dt >= datetime.now(timezone.utc)
        except Exception:
            return True
    return False

def _subscription_status_for_user(user_id: str) -> dict:
    """Subscription snapshot for a registered user."""
    res = sb.table("users").select("subscription_status,trial_ends_at,created_at,role,plan").eq("id", user_id).execute()
    if not res.data:
        return {"subscription_active": False, "subscription_status": None, "trial_ends_at": None, "is_trial": False, "plan": None}
    row = res.data[0]
    if row.get("role") == "admin":
        return {
            "subscription_active": True,
            "subscription_status": row.get("subscription_status") or "active",
            "trial_ends_at": row.get("trial_ends_at"),
            "is_trial": False,
            "plan": row.get("plan"),
        }
    status = (row.get("subscription_status") or "").lower()
    trial_ends = _ensure_full_trial_period(user_id, row) if status == "trial" else row.get("trial_ends_at")
    active = _subscription_active_for_user(user_id)
    is_trial = status == "trial" and active
    return {
        "subscription_active": active,
        "subscription_status": status or None,
        "trial_ends_at": trial_ends,
        "is_trial": is_trial,
        "plan": row.get("plan"),
    }

def check_subscription(token: str):
    if not sb:
        return True
    try:
        result = sb.table("invite_codes").select("status,expires_at").eq("code", token).execute()
        if result.data and len(result.data) > 0:
            row = result.data[0]
            if row.get("status") != "active":
                return False
            exp = row.get("expires_at")
            if exp:
                from datetime import datetime, timezone
                try:
                    if isinstance(exp, str):
                        exp_dt = datetime.fromisoformat(exp.replace("Z", "+00:00"))
                    else:
                        exp_dt = exp
                    if exp_dt.tzinfo is None:
                        exp_dt = exp_dt.replace(tzinfo=timezone.utc)
                    if exp_dt < datetime.now(timezone.utc):
                        return False
                except Exception:
                    pass
            return True
        try:
            auth = resolve_auth(token)
            if auth["kind"] == "user" and auth.get("user_id"):
                return _subscription_active_for_user(auth["user_id"])
        except HTTPException:
            pass
        return is_valid_invite_code(token)
    except Exception:
        try:
            auth = resolve_auth(token)
            if auth["kind"] == "user" and auth.get("user_id"):
                return _subscription_active_for_user(auth["user_id"])
        except HTTPException:
            pass
        return is_valid_invite_code(token)

_invite_codes_cache: Optional[set] = None
_invite_codes_cache_at: float = 0.0
INVITE_CODES_CACHE_SEC = 60

def invalidate_invite_codes_cache() -> None:
    global _invite_codes_cache, _invite_codes_cache_at
    _invite_codes_cache = None
    _invite_codes_cache_at = 0.0

def get_active_invite_codes() -> set:
    global _invite_codes_cache, _invite_codes_cache_at
    import time as _t
    from datetime import datetime, timezone
    now = _t.time()
    if _invite_codes_cache is not None and now - _invite_codes_cache_at < INVITE_CODES_CACHE_SEC:
        return _invite_codes_cache
    if not sb:
        _invite_codes_cache = set(VALID_CODES)
        _invite_codes_cache_at = now
        return _invite_codes_cache
    try:
        result = sb.table("invite_codes").select("code,status,expires_at,is_deleted").eq("status", "active").eq("is_deleted", False).execute()
        codes: set = set()
        utc_now = datetime.now(timezone.utc)
        for row in result.data or []:
            if row.get("is_deleted"):
                continue
            code = row.get("code")
            if not code:
                continue
            exp = row.get("expires_at")
            if exp:
                try:
                    exp_dt = datetime.fromisoformat(exp.replace("Z", "+00:00")) if isinstance(exp, str) else exp
                    if exp_dt.tzinfo is None:
                        exp_dt = exp_dt.replace(tzinfo=timezone.utc)
                    if exp_dt < utc_now:
                        continue
                except Exception:
                    pass
            codes.add(code)
        if codes:
            _invite_codes_cache = codes
            _invite_codes_cache_at = now
            return codes
    except Exception:
        pass
    _invite_codes_cache = set(VALID_CODES)
    _invite_codes_cache_at = now
    return _invite_codes_cache

def is_valid_invite_code(code: Optional[str]) -> bool:
    if not code:
        return False
    return code in get_active_invite_codes() or code in VALID_CODES

async def call_groq(message, history, system_prompt):
    from groq import Groq
    client = Groq(api_key=GROQ_API_KEY)
    messages = [{"role": "system", "content": system_prompt}]
    for h in history:
        messages.append({"role": h["role"], "content": h["content"]})
    messages.append({"role": "user", "content": message})
    response = client.chat.completions.create(
        model="llama-3.3-70b-versatile",
        messages=messages,
        max_tokens=800,
    )
    return response.choices[0].message.content

async def call_gemini(message, history, system_prompt):
    import google.generativeai as genai
    genai.configure(api_key=GEMINI_API_KEY)
    model = genai.GenerativeModel(model_name="gemini-flash-latest", system_instruction=system_prompt)
    chat_history = [{"role": "user" if h["role"]=="user" else "model", "parts": [h["content"]]} for h in history]
    chat = model.start_chat(history=chat_history)
    return chat.send_message(message).text

async def call_claude(message, history, system_prompt):
    import anthropic
    client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
    messages = [{"role": h["role"], "content": h["content"]} for h in history]
    messages.append({"role": "user", "content": message})
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=800,
        messages=messages
    )
