def verify_admin(x_token: Optional[str]) -> str:
    """Require a logged-in user with role=admin (JWT via x-token)."""
    if not sb:
        raise HTTPException(status_code=503, detail=DB_UNCONFIGURED_MSG)
    auth = resolve_auth(x_token, context="admin")
    if auth["kind"] != "user" or not auth.get("user_id"):
        _api_error(
            401,
            "invalid_session",
            "Admin access requires a logged-in account. Please sign in with email and password.",
            "Invalid session",
        )
    user_id = auth["user_id"]
    res = sb.table("users").select("email,role").eq("id", user_id).execute()
    if not res.data:
        raise HTTPException(status_code=401, detail="User not found")
    row = res.data[0]
    role = row.get("role")
    if role != "admin":
        if BOOTSTRAP_ADMIN_EMAIL:
            email = (row.get("email") or "").lower().strip()
            if email == BOOTSTRAP_ADMIN_EMAIL:
                admins = sb.table("users").select("id").eq("role", "admin").limit(1).execute()
                if not admins.data:
                    sb.table("users").update({"role": "admin"}).eq("id", user_id).execute()
                    return user_id
        raise HTTPException(status_code=403, detail="Admin access required")
    return user_id

def match_promotion(token: str):
    if not sb:
        return None
    try:
        from datetime import date
        auth = resolve_auth(token)
        prof_res = profile_query(auth).execute()
        if not prof_res.data:
            return None
        prof = prof_res.data[0]
        if not prof.get("consent_marketing"):
            return None
        promo_res = sb.table("promotions").select("*").eq("active", True).eq("is_deleted", False).order("created_at", desc=True).execute()
        today = date.today()
        user_country = prof.get("country") or ""
        user_city = (prof.get("city") or "").lower()
        user_zip = prof.get("zip") or ""
        user_child_count = prof.get("child_count") or 0
        user_pregnancy = bool(prof.get("pregnancy_active"))
        raw_dates = prof.get("children_birthdates") or []
        child_ages = []
        for bd in raw_dates:
            try:
                birth = date.fromisoformat(bd)
                m = (today.year - birth.year) * 12 + (today.month - birth.month)
                if today.day < birth.day:
                    m -= 1
                child_ages.append(max(0, m))
            except Exception:
                pass
        for p in (promo_res.data or []):
            if p.get("expires_at"):
                try:
                    if date.fromisoformat(p["expires_at"]) < today:
                        continue
                except Exception:
                    pass
            if p.get("target_countries") and user_country not in p["target_countries"]:
                continue
            if p.get("target_cities") and user_city not in [x.lower() for x in p["target_cities"]]:
                continue
            if p.get("target_zips") and user_zip not in p["target_zips"]:
                continue
            if p.get("child_count_min") is not None and user_child_count < p["child_count_min"]:
                continue
            if p.get("child_count_max") is not None and user_child_count > p["child_count_max"]:
                continue
            if p.get("target_pregnancy") is not None and user_pregnancy != p["target_pregnancy"]:
                continue
            age_min = p.get("child_age_min_months")
            age_max = p.get("child_age_max_months")
            if age_min is not None or age_max is not None:
                lo = age_min if age_min is not None else 0
                hi = age_max if age_max is not None else 9999
            if not any(lo <= a <= hi for a in child_ages):
                continue
            if not _promotion_matches_lang(p, prof.get("lang")):
                continue
            return p
    except Exception:
        return None
    return None
