@app.get("/admin/health")
async def admin_health(x_token: Optional[str] = Header(None)):
    admin_user_id = verify_admin(x_token)
    admin_row = sb.table("users").select("email,name,role").eq("id", admin_user_id).execute()
    admin_info = (admin_row.data or [{}])[0]
    status = {
        "admin": {
            "ok": True,
            "user_id": admin_user_id,
            "email": admin_info.get("email"),
            "name": admin_info.get("name"),
            "role": admin_info.get("role"),
        }
    }
    try:
        if GROQ_API_KEY:
            from groq import Groq
            client = Groq(api_key=GROQ_API_KEY)
            client.chat.completions.create(model="llama-3.3-70b-versatile", messages=[{"role":"user","content":"hi"}], max_tokens=1)
            status["groq"] = {"ok": True, "msg": "online"}
        else:
            status["groq"] = {"ok": False, "msg": "no key"}
    except Exception as e:
        status["groq"] = {"ok": False, "msg": str(e)[:120]}
    try:
        if GEMINI_API_KEY:
            import google.generativeai as genai
            genai.configure(api_key=GEMINI_API_KEY)
            m = genai.GenerativeModel("gemini-flash-latest")
            m.generate_content("hi", generation_config={"max_output_tokens":1})
            status["gemini"] = {"ok": True, "msg": "online"}
        else:
            status["gemini"] = {"ok": False, "msg": "no key"}
    except Exception as e:
        status["gemini"] = {"ok": False, "msg": str(e)[:120]}
    try:
        if ANTHROPIC_API_KEY:
            import anthropic
            client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
            client.messages.create(model="claude-haiku-4-5-20251001", max_tokens=1, messages=[{"role":"user","content":"hi"}])
            status["claude"] = {"ok": True, "msg": "online"}
        else:
            status["claude"] = {"ok": False, "msg": "no key"}
    except Exception as e:
        msg = str(e)
        if "credit balance" in msg.lower():
            status["claude"] = {"ok": False, "msg": "out of credits"}
        else:
            status["claude"] = {"ok": False, "msg": msg[:120]}
    if RESEND_API_KEY:
        status["resend"] = {"ok": True, "msg": "configured"}
    else:
        status["resend"] = {"ok": False, "msg": "no key"}
    return status

@app.get("/admin/usage")
async def admin_usage(x_token: Optional[str] = Header(None)):
    verify_admin(x_token)
    est_cost = sum(USAGE_LOG[p] * COST_PER_CALL.get(p, 0) for p in ("groq","gemini","claude"))
    days = max(1, (_time.time() - USAGE_LOG["since"]) / 86400)
    return {
        "calls": {"groq": USAGE_LOG["groq"], "gemini": USAGE_LOG["gemini"], "claude": USAGE_LOG["claude"]},
        "estimated_cost_usd": round(est_cost, 4),
        "since_days": round(days, 1),
    }

ACTIVITY_LOG_SORT_COLUMNS = frozenset({"created_at", "user_id", "action", "entity_type"})

def _activity_log_order(sort_by: Optional[str], sort_dir: Optional[str]):
    field = sort_by if sort_by in ACTIVITY_LOG_SORT_COLUMNS else "created_at"
    descending = (sort_dir or "desc").strip().lower() != "asc"
    return field, descending

@app.get("/admin/activity_log")
async def admin_list_activity_log(
    x_token: Optional[str] = Header(None),
    action: Optional[str] = Query(None),
    entity_type: Optional[str] = Query(None),
    user_id: Optional[str] = Query(None),
    from_date: Optional[str] = Query(None),
    to_date: Optional[str] = Query(None),
    sort_by: Optional[str] = Query("created_at"),
    sort_dir: Optional[str] = Query("desc"),
    limit: int = Query(100, ge=1, le=500),
    offset: int = Query(0, ge=0),
):
    verify_admin(x_token)
    if not sb:
        return {"entries": [], "total": 0, "error": "Database not configured"}
    try:
        q = sb.table(ACTIVITY_LOG_TABLE).select("*", count="exact")
        if action:
            q = q.eq("action", action.strip())
        if entity_type:
            q = q.eq("entity_type", entity_type.strip())
        if user_id:
            q = q.eq("user_id", user_id.strip())
        if from_date:
            fd = from_date.strip()
            if len(fd) == 10:
                fd = f"{fd}T00:00:00"
            q = q.gte("created_at", fd)
        if to_date:
            td = to_date.strip()
            if len(td) == 10:
                td = f"{td}T23:59:59.999999"
            q = q.lte("created_at", td)
        order_field, order_desc = _activity_log_order(sort_by, sort_dir)
        result = q.order(order_field, desc=order_desc).range(offset, offset + limit - 1).execute()
        entries = _attach_actor_names(result.data or [])
        return {"entries": entries, "total": result.count or len(entries)}
    except Exception as e:
        return {"entries": [], "total": 0, "error": str(e)}

