@app.put("/admin/offers/{offer_id}")
async def update_offer(offer_id: str, req: OfferUpdate, x_token: Optional[str] = Header(None)):
    admin_id = verify_admin(x_token)
    if not sb:
        raise HTTPException(status_code=500, detail="Database not configured")
    offer_key = offer_id.strip()
    if not offer_key:
        raise HTTPException(status_code=400, detail="offer id is required")
    try:
        before_snap = _offer_log_snapshot(offer_key)
        data: dict = {}
        if req.title is not None:
            title = req.title.strip()
            if not title:
                raise HTTPException(status_code=400, detail="title cannot be empty")
            data["title"] = title
        if req.body is not None:
            body = req.body.strip()
            if not body:
                raise HTTPException(status_code=400, detail="body cannot be empty")
            data["body"] = body
        if req.lang is not None:
            data["lang"] = req.lang.strip() or "all"
        if req.badge is not None:
            data["badge"] = req.badge or None
        if req.link is not None:
            data["link"] = req.link.strip() or None
        if req.expires_at is not None:
            data["expires_at"] = req.expires_at or None
        if req.image_key is not None:
            data["image_key"] = req.image_key or None
        if not data and req.region_ids is None:
            raise HTTPException(status_code=400, detail="No fields to update")
        row = None
        if data:
            result = sb.table(OFFERS_TABLE).update(data).eq("id", offer_key).execute()
            if not result.data:
                raise HTTPException(status_code=404, detail="Offer not found")
            row = result.data[0]
        if req.region_ids is not None:
            _sync_offer_regions(offer_key, req.region_ids)
            if row is None:
                fetch = sb.table(OFFERS_TABLE).select("*").eq("id", offer_key).limit(1).execute()
                if not fetch.data:
                    raise HTTPException(status_code=404, detail="Offer not found")
                row = fetch.data[0]
        if row:
            row = enrich_image(row, "offers")
            attached = _attach_regions_to_offers([row])
            row = attached[0] if attached else row
        _log_activity(
            admin_id, "update", "offer", offer_key,
            value_before=before_snap,
            value_after=_offer_log_snapshot(offer_key),
        )
        return {"ok": True, "offer": row}
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

