@app.get("/admin/user_data")
async def admin_get_user_data(
    user_id: Optional[str] = None,
    token: Optional[str] = None,
    x_token: Optional[str] = Header(None),
):
    verify_admin(x_token)
    if not sb:
        return {"data": {}, "meta": {}}
    if not user_id and not token:
        raise HTTPException(status_code=400, detail="user_id or token query param required")
    try:
        rows: list = []
        seen_keys: set = set()

        def merge_rows(batch: list) -> None:
            for row in batch or []:
                key = row.get("key")
                if not key or key in seen_keys:
                    continue
                seen_keys.add(key)
                rows.append(row)

        if user_id:
            res = (
                sb.table("user_data")
                .select("key,value,updated_at")
                .eq("user_id", user_id)
                .execute()
            )
            merge_rows(res.data)
            try:
                prof = (
                    sb.table("profiles")
                    .select("token")
                    .eq("user_id", user_id)
                    .limit(1)
                    .execute()
                )
                prof_token = (prof.data or [{}])[0].get("token")
                if prof_token:
                    res2 = (
                        sb.table("user_data")
                        .select("key,value,updated_at")
                        .eq("token", prof_token)
                        .execute()
                    )
                    merge_rows(res2.data)
            except Exception:
                pass
        else:
            res = (
                sb.table("user_data")
                .select("key,value,updated_at")
                .eq("token", token)
                .execute()
            )
            merge_rows(res.data)

        data = {r["key"]: r["value"] for r in rows}
        meta = {r["key"]: {"updated_at": r.get("updated_at")} for r in rows}
        transaction_counts = _transaction_counts_by_user_data_key(user_id) if user_id else {}
        return {"data": data, "meta": meta, "transaction_counts": transaction_counts}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

