def _rag_chunk_counts(source_ids: List[str]) -> dict:
    counts = {sid: 0 for sid in source_ids}
    if not sb or not source_ids:
        return counts
    try:
        res = (
            sb.table("rag_chunks")
            .select("source_id")
            .in_("source_id", source_ids)
            .execute()
        )
        for row in res.data or []:
            sid = row.get("source_id")
            if sid in counts:
                counts[sid] += 1
    except Exception:
        pass
    return counts


