class TesterInviteRequest(BaseModel):
    first_name: str
    last_name: str
    email: str
    plan: str
    invite_code: str
    lang: str = "el"
    create_supabase_user: bool = False
    temporary_password: Optional[str] = None
    require_password_change: bool = True

@app.post("/admin/invite_tester")
async def invite_tester(req: TesterInviteRequest, x_token: Optional[str] = Header(None)):
    admin_id = verify_admin(x_token)
    if not is_valid_invite_code(req.invite_code):
        raise HTTPException(status_code=400, detail="Invalid invite code.")
    email = req.email.lower().strip()
    full_name = f"{req.first_name} {req.last_name}".strip()
    plan_label = "Premium" if req.plan == "premium" else "Starter"
    try:
        if req.create_supabase_user:
            if not sb:
                raise HTTPException(status_code=500, detail=DB_UNCONFIGURED_MSG)
            existing = sb.table("users").select("id").eq("email", email).execute()
            if existing.data:
                raise HTTPException(status_code=400, detail="Email already registered.")
            temp_pw = (req.temporary_password or "").strip()
            if temp_pw and len(temp_pw) < 6:
                raise HTTPException(status_code=400, detail="Temporary password must be at least 6 characters.")
            user_id = supabase_create_auth_user(
                email,
                {
                    "name": full_name,
                    "invite_code": req.invite_code,
                    "plan": req.plan,
                },
                password=temp_pw or None,
            )
            must_change = bool(temp_pw and req.require_password_change)
            try:
                sb.table("users").insert({
                    "id": user_id,
                    "email": email,
                    "name": full_name,
                    "invite_code": req.invite_code,
                    "role": None,
                    "must_change_password": must_change,
                    **_tester_plan_fields(req.plan),
                }).execute()
            except Exception as e:
                try:
                    sb.auth.admin.delete_user(user_id)
                except Exception:
                    pass
                raise HTTPException(status_code=500, detail=_user_insert_error_detail(e))
            email_error = _send_tester_invite_email(
                req.first_name,
                email,
                req.invite_code,
                plan_label,
                auth_account_ready=True,
                temporary_password=temp_pw or None,
            )
            _log_activity(
                admin_id, "invite_tester", "user", user_id,
                value_after={"email": email, "name": full_name, "plan": req.plan, "invite_code": req.invite_code, "user_created": True},
            )
            return {
                "ok": True,
                "user_id": user_id,
                "user_created": True,
                "mode": "supabase_user",
                "email_sent": email_error is None and bool(RESEND_API_KEY),
                "email_error": email_error,
            }

        if not RESEND_API_KEY:
            raise HTTPException(status_code=500, detail="Email service not configured.")
        email_error = _send_tester_invite_email(req.first_name, email, req.invite_code, plan_label)
        if email_error:
            raise HTTPException(status_code=500, detail=email_error)
        _log_activity(
            admin_id, "invite_tester", "user", email,
            value_after={"email": email, "name": full_name, "plan": req.plan, "invite_code": req.invite_code, "user_created": False},
        )
        return {"ok": True, "mode": "instructions", "user_created": False}
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


