@app.post("/auth/change-password")
def change_password(req: ChangePasswordRequest, x_token: Optional[str] = Header(None)):
    if not sb:
        raise HTTPException(status_code=500, detail=DB_UNCONFIGURED_MSG)
    auth = resolve_auth(x_token)
    if auth["kind"] != "user" or not auth.get("user_id"):
        raise HTTPException(status_code=401, detail="Not authenticated.")
    user_id = auth["user_id"]
    new_password = (req.password or "").strip()
    if len(new_password) < 6:
        raise HTTPException(status_code=400, detail="Password must be at least 6 characters.")
    u = sb.table("users").select("email,must_change_password").eq("id", user_id).execute()
    if not u.data:
        raise HTTPException(status_code=404, detail="User not found.")
    row = u.data[0]
    email = row.get("email") or ""
    if not row.get("must_change_password"):
        if not req.current_password:
            raise HTTPException(status_code=400, detail="Current password is required.")
        try:
            _sign_in_with_password_as_user(email, req.current_password.strip())
        except Exception:
            raise HTTPException(status_code=401, detail="Current password is incorrect.")
    try:
        sb.auth.admin.update_user_by_id(user_id, {"password": new_password})
        sb.table("users").update({"must_change_password": False}).eq("id", user_id).execute()
        session = _sign_in_with_password_as_user(email, new_password)
        access_token = session.session.access_token
        return {"ok": True, "token": access_token}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

import resend as resend_client

@app.post("/auth/forgot-password")
def forgot_password(req: EmailRequest):
    if not sb:
        raise HTTPException(status_code=500, detail=DB_UNCONFIGURED_MSG)
    try:
        resend_client.api_key = RESEND_API_KEY
        res = sb.table("users").select("id,email,name").eq("email", req.email.lower().strip()).execute()
        if not res.data:
            return {"ok": True}
        user = res.data[0]
        import secrets
        from datetime import datetime, timedelta
        token = secrets.token_urlsafe(32)
        expires = (datetime.utcnow() + timedelta(hours=2)).isoformat()
        sb.table("users").update({"reset_token": token, "reset_token_expires": expires}).eq("id", user["id"]).execute()
        reset_url = f"{APP_URL}?reset={token}"
        resend_client.Emails.send({
            "from": RESEND_FROM,
            "to": user["email"],
            "subject": "Reset your HeyMaa password",
            "html": f"<p>Hi {user.get('name','')},</p><p>Click <a href='{reset_url}'>here</a> to reset your password. Link expires in 2 hours.</p><p>If you did not request this, ignore this email.</p>"
        })
        return {"ok": True}
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

@app.post("/auth/reset-password")
def reset_password(req: ResetPasswordRequest):
    if not sb:
        raise HTTPException(status_code=500, detail=DB_UNCONFIGURED_MSG)
    try:
        from datetime import datetime
        res = sb.table("users").select("*").eq("reset_token", req.token).execute()
        if not res.data:
            raise HTTPException(status_code=400, detail="Invalid or expired reset link.")
        user = res.data[0]
        expires = user.get("reset_token_expires","")
        if expires and datetime.utcnow().isoformat() > expires[:19]:
            raise HTTPException(status_code=400, detail="Reset link has expired.")
        sb.auth.admin.update_user_by_id(user["id"], {"password": req.password})
        sb.table("users").update({"reset_token": None, "reset_token_expires": None}).eq("id", user["id"]).execute()
        return {"ok": True}
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


